/**
 * Unit Tests for Attribute Detection Stage
 *
 * TDD APPROACH: These tests are written FIRST and MUST FAIL before implementation.
 * They test all detector types, derived attributes, and edge cases.
 *
 * Tests cover:
 * - Pattern-based detection (regexAny, containsAny, startsWith)
 * - Derived attribute logic (selfSent, domain lookups)
 * - Error handling and edge cases
 * - Configuration validation
 * - Performance requirements
 */

import {
  executeAttributeDetection,
  AttributeDetectionStageConfig,
  AttributeDetectionResult,
} from '../../src/stages/attribute-detection';
import { ClassificationResult } from '../../src/types';
import { createMockEmail, setupTestEnvironment } from '../helpers/test-fixtures';

describe('AttributeDetectionStage', () => {
  let stageConfig: AttributeDetectionStageConfig;

  // Helper to create stage config with detectors
  function createStageConfig() {
    const { config } = setupTestEnvironment();
    return {
      settings: {
        attributeProcessing: {
          detectSelfSent: true,
          resolveDomains: true,
          deriveContextFlags: true,
        },
      },
      attributes: {
        schema: config.attributes.schema,
        detectors: [
          {
            attribute: 'hasAmount',
            field: 'body' as const,
            operation: 'regexAny' as const,
            values: ['\\$\\d+', 'USD', 'amount due'],
            confidence: 0.8,
            parallelSafe: true,
          },
          {
            attribute: 'hasDueDate',
            field: 'body' as const,
            operation: 'containsAny' as const,
            values: ['due by', 'due on', 'due date', 'pay by', 'payment due'],
            confidence: 0.8,
            parallelSafe: true,
          },
          {
            attribute: 'requiresAction',
            field: 'body' as const,
            operation: 'containsAny' as const,
            values: ['please review', 'action required', 'respond', 'reply', 'follow up'],
            confidence: 0.7,
            parallelSafe: true,
          },
          {
            attribute: 'trackingPresent',
            field: 'body' as const,
            operation: 'containsAny' as const,
            values: ['tracking number', 'track your package'],
            confidence: 0.9,
            parallelSafe: true,
          },
          {
            attribute: 'unsubscribePresent',
            field: 'body' as const,
            operation: 'containsAny' as const,
            values: ['unsubscribe', 'manage preferences'],
            confidence: 0.95,
            parallelSafe: true,
          },
          {
            attribute: 'requiresAction',
            field: 'subject' as const,
            operation: 'startsWith' as const,
            values: ['ACTION REQUIRED', 'URGENT'],
            confidence: 0.9,
            parallelSafe: true,
          },
        ],
        derived: {
          selfSent: {
            logic: 'fromAddress in userAddresses AND allRecipients in userAddresses AND NOT listId',
            notes: 'Email sent from user to self, excluding mailing lists',
            parallelSafe: true,
            dependencies: [],
          },
          fromFinancialInstitution: {
            logic: 'fromDomain in financialDomains OR fromDomain in domainLookup.financial',
            notes: 'Email from known financial institution',
            parallelSafe: true,
            dependencies: [],
          },
          fromNewsletterSource: {
            logic: 'fromDomain in newsletterDomains OR listId header present',
            notes: 'Email from newsletter or mailing list source',
            parallelSafe: true,
            dependencies: [],
          },
          fromLogisticsCarrier: {
            logic: 'fromDomain in logisticsDomains',
            notes: 'Email from shipping/logistics carrier',
            parallelSafe: true,
            dependencies: [],
          },
        },
        attributeBonusMap: {
          hasAmount: {
            financial: 2,
            commerceLogistics: 1,
          },
          requiresAction: {
            actionable: 3,
            financial: 1,
          },
          trackingPresent: {
            commerceLogistics: 3,
            travel: 1,
          },
        },
      },
      performanceCache: {
        financialDomains: ['chase.com', 'bankofamerica.com', 'paypal.com'],
        newsletterDomains: ['medium.com', 'substack.com'],
        logisticsDomains: ['fedex.com', 'ups.com', 'usps.com'],
      },
    };
  }

  beforeEach(() => {
    stageConfig = createStageConfig();
  });

  describe('Pattern-based Detection', () => {
    test('should detect hasAmount attribute with regex patterns', () => {
      const { session, result } = setupTestEnvironment();
      const emailWithAmount = createMockEmail({
        bodyPlain: 'Your invoice shows an amount due of $123.45 USD.',
        subject: 'Invoice Due',
      });

      const detectedAttrs = executeAttributeDetection(emailWithAmount, session, result, stageConfig);

      const detectedAttributes = detectedAttrs.map((attr) => ({
        attributeName: attr.attribute,
        attributeValue: attr.detected,
        detectionMethod: attr.detectionMethod === 'direct' ? ('pattern' as const) : ('derived' as const),
        detectionEvidence: attr.reason || '',
        confidence: attr.confidence,
      }));
      expect(detectedAttributes).toContainEqual(
        expect.objectContaining({
          attributeName: 'hasAmount',
          attributeValue: true,
          detectionMethod: 'pattern',
          detectionEvidence: expect.stringContaining('$123.45'),
          confidence: expect.any(Number),
        })
      );
      expect(result.explainabilityTrace.stageTimings['attributeDetection']).toBeGreaterThanOrEqual(0);
    });

    test('should detect hasDueDate attribute with containsAny operation', () => {
      const { session, result } = setupTestEnvironment();
      const emailWithDueDate = createMockEmail({
        bodyPlain: 'Payment is due by March 15th, 2025.',
        subject: 'Payment Reminder',
      });

      const detectedAttrs = executeAttributeDetection(emailWithDueDate, session, result, stageConfig);

      const detectedAttributes = detectedAttrs.map((attr) => ({
        attributeName: attr.attribute,
        attributeValue: attr.detected,
        detectionMethod: attr.detectionMethod === 'direct' ? ('pattern' as const) : ('derived' as const),
        detectionEvidence: attr.reason || '',
        confidence: attr.confidence,
      }));
      expect(detectedAttributes).toContainEqual(
        expect.objectContaining({
          attributeName: 'hasDueDate',
          attributeValue: true,
          detectionMethod: 'pattern',
          detectionEvidence: expect.stringContaining('due by'),
        })
      );
    });

    test('should detect requiresAction attribute from subject with startsWith operation', () => {
      const { session, result } = setupTestEnvironment();
      const emailWithActionSubject = createMockEmail({
        subject: 'ACTION REQUIRED: Verify your account',
        bodyPlain: 'Please verify your account information.',
      });

      const detectedAttrs = executeAttributeDetection(emailWithActionSubject, session, result, stageConfig);

      const detectedAttributes = detectedAttrs.map((attr) => ({
        attributeName: attr.attribute,
        attributeValue: attr.detected,
        detectionMethod: attr.detectionMethod === 'direct' ? ('pattern' as const) : ('derived' as const),
        detectionEvidence: attr.reason || '',
        confidence: attr.confidence,
      }));
      expect(detectedAttributes).toContainEqual(
        expect.objectContaining({
          attributeName: 'requiresAction',
          attributeValue: true,
          detectionMethod: 'pattern',
          detectionEvidence: expect.stringContaining('ACTION REQUIRED'),
        })
      );
    });

    test('should detect trackingPresent attribute', () => {
      const { session, result } = setupTestEnvironment();
      const emailWithTracking = createMockEmail({
        bodyPlain: 'Your package has shipped! Track your package with number 1Z123456789.',
        subject: 'Package Shipped',
      });

      const detectedAttrs = executeAttributeDetection(emailWithTracking, session, result, stageConfig);

      const detectedAttributes = detectedAttrs.map((attr) => ({
        attributeName: attr.attribute,
        attributeValue: attr.detected,
        detectionMethod: attr.detectionMethod === 'direct' ? ('pattern' as const) : ('derived' as const),
        detectionEvidence: attr.reason || '',
        confidence: attr.confidence,
      }));
      expect(detectedAttributes).toContainEqual(
        expect.objectContaining({
          attributeName: 'trackingPresent',
          attributeValue: true,
          detectionMethod: 'pattern',
        })
      );
    });

    test('should detect unsubscribePresent attribute', () => {
      const { session, result } = setupTestEnvironment();
      const emailWithUnsubscribe = createMockEmail({
        bodyPlain: 'Weekly newsletter content. To unsubscribe, click here.',
        subject: 'Weekly Newsletter',
      });

      const detectedAttrs = executeAttributeDetection(emailWithUnsubscribe, session, result, stageConfig);

      const detectedAttributes = detectedAttrs.map((attr) => ({
        attributeName: attr.attribute,
        attributeValue: attr.detected,
        detectionMethod: attr.detectionMethod === 'direct' ? ('pattern' as const) : ('derived' as const),
        detectionEvidence: attr.reason || '',
        confidence: attr.confidence,
      }));
      expect(detectedAttributes).toContainEqual(
        expect.objectContaining({
          attributeName: 'unsubscribePresent',
          attributeValue: true,
          detectionMethod: 'pattern',
        })
      );
    });

    test('should handle multiple pattern matches for same attribute', () => {
      const { session, result } = setupTestEnvironment();
      const emailWithMultipleAmounts = createMockEmail({
        bodyPlain: 'Invoice total: $50.00 USD. Amount due: $25.00. Previous balance was $25.00.',
        subject: 'Invoice Statement',
      });

      const detectedAttrs = executeAttributeDetection(emailWithMultipleAmounts, session, result, stageConfig);

      const detectedAttributes = detectedAttrs.map((attr) => ({
        attributeName: attr.attribute,
        attributeValue: attr.detected,
        detectionMethod: attr.detectionMethod === 'direct' ? ('pattern' as const) : ('derived' as const),
        detectionEvidence: attr.reason || '',
        confidence: attr.confidence,
      }));
      const amountAttribute = detectedAttributes.find((attr) => attr.attributeName === 'hasAmount');
      expect(amountAttribute).toBeDefined();
      expect(amountAttribute?.detectionEvidence).toMatch(/\$\d+/);
    });

    test('should be case insensitive for pattern matching', () => {
      const { session, result } = setupTestEnvironment();
      const emailCaseInsensitive = createMockEmail({
        bodyPlain: 'PAYMENT DUE BY MARCH 15TH',
        subject: 'URGENT PAYMENT NOTICE',
      });

      const detectedAttrs = executeAttributeDetection(emailCaseInsensitive, session, result, stageConfig);

      const detectedAttributes = detectedAttrs.map((attr) => ({
        attributeName: attr.attribute,
        attributeValue: attr.detected,
        detectionMethod: attr.detectionMethod === 'direct' ? ('pattern' as const) : ('derived' as const),
        detectionEvidence: attr.reason || '',
        confidence: attr.confidence,
      }));
      expect(detectedAttributes).toContainEqual(
        expect.objectContaining({
          attributeName: 'hasDueDate',
          attributeValue: true,
        })
      );
    });
  });

  describe('Derived Attributes', () => {
    test('should detect selfSent attribute for user-to-user emails', () => {
      const { session, result } = setupTestEnvironment();
