/**
 * AI Feature Extraction Stage
 *
 * Stage 8a of the EmailCategorizer pipeline. Uses LangChain OpenAI integration with GPT-4o-mini
 * for semantic feature extraction with JSON schema validation and batch processing support.
 *
 * This stage is responsible for:
 * - Calling OpenAI API with structured prompts and email content
 * - Validating AI responses against JSON schema
 * - Extracting semantic intent and category enhancements
 * - Validating evidence grounding (quoted phrases must exist in email)
 * - Providing retry logic and error handling for API failures
 * - Supporting batch processing with concurrent API calls
 */

import Ajv from 'ajv';
import { logger } from '../utils/logger';
import type { AIClient } from '../ai/ai-client';
import { OpenAIClient } from '../ai/openai-client';
import { ClassificationSession, EmailMessage } from '../types';
import { ClassificationResult, CandidateScore } from '../types/classification-result';
import { AttributeContext } from '../types/attribute-context';
import {
  formatEmailAddress,
  formatObjectForTemplate,
  getEmailBodyText,
  interpolateTemplate,
} from '../utils/template-utils';

// Configuration interface for AI feature extraction
export interface AIFeatureExtractionConfig {
  openai: {
    apiKey: string;
    model: string;
    temperature: number;
    responseFormat: 'json_schema' | 'json_object'; // Support both for backward compatibility
    client?: AIClient; // Optional injected AI client (for dependency injection in tests)
  };
  prompts: {
    systemPrompt: string[];
    userPrompt: string[];
  };
  featureExtractionSchema: {
    name?: string;
    description?: string;
    schema: Record<string, unknown>;
    strict?: boolean;
  };
  retryPolicy: {
    maxRetries: number;
    backoffMs: number;
  };
}

// Semantic intent extracted by AI
export interface SemanticIntent {
  primaryPurpose: 'notification' | 'request' | 'update' | 'alert';
  actionRequired: 'none' | 'view' | 'respond' | 'complete';
  urgencyLevel: 'none' | 'low' | 'medium' | 'high';
}

// Evidence structure for category enhancements
export interface CategoryEvidence {
  quotedPhrases: string[];
  keywords: string[];
  reasoning: string;
}

// Category enhancement from AI analysis
export interface CategoryEnhancement {
  applies: boolean;
  confidenceBoost: number;
  evidence: CategoryEvidence;
}

// Complete feature extraction result from AI
export interface FeatureExtractionData {
  semanticIntent: SemanticIntent;
  categoryEnhancements: Record<string, CategoryEnhancement>;
}

// Evidence validation result
export interface EvidenceValidation {
  validPhrases: string[];
  invalidPhrases: string[];
  fabricationDetected: boolean;
}

// Complete stage result interface
export interface FeatureExtractionResult {
  featureExtraction: FeatureExtractionData;
  validationPassed: boolean;
  validationErrors: string[];
  evidenceValidation: EvidenceValidation;
  processingDurationMs: number;
  tokenUsage: number;
  apiCallCount: number;
  retryCount: number;
}

/**
 * AI Feature Extraction Stage Implementation
 *
 * Integrates with OpenAI GPT-4o-mini to extract semantic features and enhance
 * category classifications with evidence-grounded analysis.
 *
 * CANONICAL SIGNATURE: (email, session, result, config) => Promise<void>
 * Mutates result object by storing feature extraction data in explainabilityTrace
 */
export async function aiFeatureExtractionStage(
  email: EmailMessage,
  session: ClassificationSession,
  result: ClassificationResult,
  config: AIFeatureExtractionConfig
): Promise<void> {
  const startTime = Date.now();
  let retryCount = 0;
  const apiCallCount = 0;

  // Validate inputs
  validateInputs(email, session, result, config);

  // Extract candidate categories and detected attributes from result
  const candidateCategories = result.candidateScores;
  const detectedAttributes = result.attributeContext;

  // Use injected AI client OR create OpenAI client for backward compatibility with unit tests
  const client = config.openai.client || new OpenAIClient(config.openai.apiKey);

  // Setup JSON schema validator (only used for legacy json_object mode)
  const ajv = new Ajv();
  const validateSchema = ajv.compile(config.featureExtractionSchema.schema);

  // Retry loop for API calls
  let lastError: Error | null = null;

  while (retryCount < config.retryPolicy.maxRetries) {
    try {
      // Prepare prompts with email content interpolation
      const systemPrompt = config.prompts.systemPrompt.join('\n');
      const userPrompt = interpolateUserPrompt(
        config.prompts.userPrompt,
        email,
        candidateCategories,
        detectedAttributes
      );

      // Prepare response format based on configuration
      const responseFormat =
        config.openai.responseFormat === 'json_schema'
          ? {
              type: 'json_schema' as const,
              json_schema: {
                name: config.featureExtractionSchema.name || 'featureExtraction',
                description:
                  config.featureExtractionSchema.description ||
                  'Extract semantic features and category enhancements from email content',
                schema: config.featureExtractionSchema.schema,
                strict: config.featureExtractionSchema.strict ?? true,
              },
            }
          : { type: 'json_object' as const }; // Backward compatibility

      // Call AI client with structured outputs
      const response = await client.chatComplete({
        model: config.openai.model,
        temperature: config.openai.temperature,
        response_format: responseFormat,
        messages: [
          { role: 'system', content: systemPrompt },
          { role: 'user', content: userPrompt },
        ],
      });

      // Parse and validate response
      const rawContent = response.choices[0].message.content;
      if (!rawContent) {
        throw new Error('Empty response from OpenAI');
      }

      let featureExtractionData: FeatureExtractionData;
      try {
        featureExtractionData = JSON.parse(rawContent);
      } catch {
        throw new Error('Invalid JSON response from OpenAI');
      }

      // Schema validation: For structured outputs, OpenAI enforces the schema.
      // For backward compatibility with json_object mode, we still validate with AJV.
      const validationErrors: string[] = [];
      let validationPassed = true;

      if (config.openai.responseFormat === 'json_object') {
        // Only validate with AJV for legacy json_object mode
        validationPassed = validateSchema(featureExtractionData);

        if (!validationPassed && validateSchema.errors) {
          for (const error of validateSchema.errors) {
            validationErrors.push(`${error.instancePath} ${error.message}`);
          }
          throw new Error('Schema validation failed: ' + validationErrors.join(', '));
        }
      }
      // For json_schema mode, OpenAI has already enforced the schema, so no additional validation needed

      // Validate evidence grounding
      validateEvidenceGrounding(email, featureExtractionData);

      // Defensive check for explainabilityTrace initialization
      if (!result.explainabilityTrace) {
        throw new Error('CRITICAL: explainabilityTrace is not initialized in result object');
      }

      // Initialize explainabilityTrace.aiRouting if not exists
      if (!result.explainabilityTrace.aiRouting) {
        result.explainabilityTrace.aiRouting = {
          routingDecision: 'featureExtraction',
          highConfidenceThreshold: 0,
          aiRequiredThreshold: 0,
          skipConditions: [],
          reason: 'AI routing decision made in stage: ai-feature-extraction',
        };
      }

      // Store feature extraction data in aiResponse.extractedFeatures
      if (!result.explainabilityTrace.aiRouting.aiResponse) {
        result.explainabilityTrace.aiRouting.aiResponse = {
          extractedFeatures: featureExtractionData,
          confidence: 0,
          reasoning: 'Feature extraction completed successfully',
        };
      } else {
        result.explainabilityTrace.aiRouting.aiResponse.extractedFeatures = featureExtractionData;
      }

      // Store feature extraction data in result.aiFeatureExtraction for ai-classification stage
      result.aiFeatureExtraction = featureExtractionData;

      // Record timing for unit tests and direct stage invocations
      const durationMs = Date.now() - startTime;
      result.explainabilityTrace.stageTimings['aiFeatureExtraction'] = durationMs;

      return;
    } catch (error) {
      lastError = error as Error;
      retryCount++;

      if (retryCount < config.retryPolicy.maxRetries) {
        // Wait before retry with exponential backoff
        await new Promise((resolve) => setTimeout(resolve, config.retryPolicy.backoffMs * Math.pow(2, retryCount - 1)));
      }
    }
  }

  // All retries exhausted
  throw new Error(`AI feature extraction failed after ${config.retryPolicy.maxRetries} retries: ${lastError?.message}`);
}

/**
 * Validate input parameters
 */
function validateInputs(
  email: EmailMessage,
  session: ClassificationSession,
  result: ClassificationResult,
  config: AIFeatureExtractionConfig
): void {
  if (!email?.id && !('gmailId' in email)) {
    throw new Error('Invalid email input: id or gmailId is required');
  }

  // Allow missing subjects but log a warning - production emails might legitimately have empty subjects
  if (!email.subject) {
    logger.warn({ emailId: email.id }, 'Email has missing subject - proceeding with empty subject for classification');
  }

  if (!session?.id && !('sessionId' in session)) {
    throw new Error('Invalid session input: id or sessionId is required');
  }

  if (!result) {
    throw new Error('Classification result is required');
  }

  if (!result.candidateScores || typeof result.candidateScores !== 'object') {
    throw new Error('Candidate scores are required in result and must be an object');
  }

  if (!result.attributeContext || typeof result.attributeContext !== 'object') {
    throw new Error('Attribute context is required in result and must be an object');
  }

  // Validate candidateScores structure
  for (const [category, scoreData] of Object.entries(result.candidateScores)) {
    if (!scoreData || typeof scoreData !== 'object') {
      throw new Error(`Invalid candidate score for category ${category}: must be an object`);
    }
    if (typeof scoreData.score !== 'number') {
      throw new Error(`Invalid candidate score for category ${category}: score must be a number`);
    }
  }

  if (!config) {
    throw new Error('Configuration is required');
  }

  if (!config.openai?.apiKey || config.openai.apiKey.trim() === '') {
    throw new Error('Invalid configuration: OpenAI API key is required');
  }

  if (!config.prompts?.systemPrompt || !config.prompts?.userPrompt) {
    throw new Error('Invalid configuration: system and user prompts are required');
  }

  if (!config.featureExtractionSchema) {
    throw new Error('Invalid configuration: feature extraction schema is required');
  }
}

/**
 * Interpolate user prompt template with email content and analysis data
 *
 * Supports dynamic object path resolution with these placeholders:
 * - {email.from} - formatted email address
 * - {email.subject} - email subject
 * - {email.body} - email body text
 * - {candidateCategories} - JSON formatted candidate categories
 * - {detectedAttributes} - JSON formatted detected attributes
 */
function interpolateUserPrompt(
  userPromptTemplate: string[],
  email: EmailMessage,
  candidateCategories: Record<string, CandidateScore>,
  detectedAttributes: AttributeContext
): string {
  const template = userPromptTemplate.join('\n');

  // Create interpolation context with all available data
  const context = {
    email: {
      from: formatEmailAddress(email.from),
      subject: email.subject || '',
      body: getEmailBodyText(email),
    },
    candidateCategories: formatObjectForTemplate(candidateCategories as unknown as Record<string, unknown>),
    detectedAttributes: formatObjectForTemplate(detectedAttributes as unknown as Record<string, unknown>),
  };

  // Perform template interpolation using dynamic path resolution
  return interpolateTemplate(template, context);
}

/**
 * Validate that quoted phrases in evidence actually exist in the email content
 */
function validateEvidenceGrounding(email: EmailMessage, featureExtraction: FeatureExtractionData): EvidenceValidation {
  const emailText = (email.subject + ' ' + getEmailBodyText(email)).toLowerCase();
  const validPhrases: string[] = [];
  const invalidPhrases: string[] = [];

  // Check all quoted phrases in category enhancements
  for (const [, enhancement] of Object.entries(featureExtraction.categoryEnhancements || {})) {
    if (enhancement.evidence?.quotedPhrases) {
      for (const phrase of enhancement.evidence.quotedPhrases) {
        const normalizedPhrase = phrase.toLowerCase().trim();
        if (normalizedPhrase && emailText.includes(normalizedPhrase)) {
          validPhrases.push(phrase);
        } else if (normalizedPhrase) {
          invalidPhrases.push(phrase);
        }
      }
    }
  }

  return {
    validPhrases,
    invalidPhrases,
    fabricationDetected: invalidPhrases.length > 0,
  };
}

