/**
 * Create a mock EmailMessage with optional overrides
 *
 * @param overrides - Partial EmailMessage to override defaults
 * @returns Complete EmailMessage suitable for testing
 *
 * @example
 * const email = createMockEmail({ subject: 'Payment received' });
 * const financialEmail = createMockEmail({
 *   from: { email: 'alerts@chase.com', raw: 'alerts@chase.com' },
 *   subject: 'Your credit card statement',
 * });
 */
export function createMockEmail(overrides: Partial<EmailMessage> = {}): EmailMessage {
  return {
    id: 'test-email-id',
    threadId: 'test-thread-id',
    gmailLabels: [],
    payload: {
      mimeType: 'text/plain',
      headers: [],
    },
    subject: 'Test Subject',
    from: { email: 'test@example.com', raw: 'test@example.com' },
    to: [{ email: 'recipient@example.com', raw: 'recipient@example.com' }],
    date: new Date('2025-01-15T12:00:00Z'),
    isProcessed: false,
    processingPriority: 1,
    bodyPlain: 'Test body content',
    ...overrides,
  };
}

/**
 * Create a mock ProcessingConfig with optional overrides
 *
 * @param settingsOverride - ProcessingSettings to use (defaults to STANDARD_TEST_SETTINGS)
 * @param configOverrides - Additional top-level config overrides
 * @returns Complete ProcessingConfig suitable for testing
 *
 * @example
 * const config = createMockProcessingConfig();
 * const minimalConfig = createMockProcessingConfig(MINIMAL_TEST_SETTINGS);
 * const customConfig = createMockProcessingConfig(undefined, { version: 2 });
 */
export function createMockProcessingConfig(
  settingsOverride?: ProcessingSettings,
  configOverrides?: Partial<ProcessingConfig>
): ProcessingConfig {
  const settings = settingsOverride || STANDARD_TEST_SETTINGS;

  const domainOverrides: DomainOverrides = {};

  const domainResolution: DomainResolution = {
    mode: 'runtimeResolved',
    source: 'config/domain-sources.json',
    notes: 'Test config',
  };

  const attributes: AttributeSystem = {
    schema: {},
    detectors: [],
    derived: {},
    attributeBonusMap: {},
  };

  const attributeRelevance: AttributeRelevanceMatrix = {
    RolesLegend: {
      CORE: 'Core attribute',
      PRIMARY_BOOST: 'Primary boost',
      SECONDARY_BOOST: 'Secondary boost',
      DISAMBIGUATOR: 'Disambiguator',
      FILTER: 'Filter',
      STRUCTURAL: 'Structural',
      DERIVED_LINK: 'Derived link',
      NEUTRAL: 'Neutral',
    },
  };

  const aiPrompts: AIPromptSystem = {
    featureExtraction: {
      systemPrompt: ['Extract features from email'],
      userPrompt: ['Analyze the following email'],
      temperature: 0.1,
      maxTokens: 1000,
    },
    finalClassification: {
      systemPrompt: ['Classify email into categories'],
      userPrompt: ['Determine the primary category'],
      temperature: 0.1,
      maxTokens: 500,
    },
  };

  const featureExtractionSchema: JSONSchema = {
    type: 'object',
    properties: {},
    required: [],
    additionalProperties: false,
  };

  return {
    version: 1,
    taxonomyNotes: 'Test configuration',
    settings,
    categorySignals: {},
    domainSignalOverrides: domainOverrides,
    domainSignalResolution: domainResolution,
    topLevelCategories: {},
    attributes,
    attributeRelevance,
    aiPrompts,
    featureExtractionSchema,
    ...configOverrides,
  };
}

/**
 * Set up a complete test environment with session, email, and result
 *
 * @param configOverrides - Optional config overrides
 * @param emailOverrides - Optional email overrides
 * @param processingMode - Processing mode ('sequential' or 'parallel')
 * @returns Object containing session, email, result, and config
 *
 * @example
 * const { session, email, result, config } = setupTestEnvironment();
 * const { session, email, result } = setupTestEnvironment(
 *   { version: 2 },
 *   { subject: 'Payment received' }
 * );
 */
export function setupTestEnvironment(
  configOverrides?: Partial<ProcessingConfig>,
  emailOverrides?: Partial<EmailMessage>,
  processingMode: 'sequential' | 'parallel' = 'sequential'
) {
  const config = createMockProcessingConfig(undefined, configOverrides);
  const session = createClassificationSession(config, processingMode, 1);
  const email = createMockEmail(emailOverrides);
  const result = createClassificationResult(email.id, session.id, 0);

  return { session, email, result, config };
}

/**
 * Set up test environment with pre-initialized category scores and seeds
 * Useful for testing stages that depend on existing classification state
 *
 * @param initialScores - Map of category names to initial base scores
 * @param existingSeeds - Map of category names to existing strong indicator seeds
 * @param emailOverrides - Optional email overrides
 * @returns Object containing session, email, result, and config with initialized scores
 *
 * @example
 * const { session, result } = setupTestWithScores(
 *   { Financial: 0.1, Shopping: 0.2 },
 *   { Financial: 5 }
 * );
 */
export function setupTestWithScores(
  initialScores: Record<string, number> = {},
  existingSeeds: Record<string, number> = {},
  emailOverrides?: Partial<EmailMessage>
) {
  const { session, email, result, config } = setupTestEnvironment(undefined, emailOverrides);

  // Initialize category scores
  for (const [category, score] of Object.entries(initialScores)) {
    result.scoreBreakdown.categoryScores[category] = {
      baseScore: score,
      hardAssertionBonus: 0,
      strongIndicatorScore: 0,
      ruleScore: 0,
      attributeInfluenceScore: 0,
      finalScore: score,
      confidence: 0,
      parallelComputedComponents: [],
      computationDurationMs: 0,
      cacheHits: [],
      scoreAggregationSteps: [],
      cappingApplied: false,
    };
  }

  // Initialize strong indicator seeds
  for (const [category, seed] of Object.entries(existingSeeds)) {
    if (!result.scoreBreakdown.categoryScores[category]) {
      result.scoreBreakdown.categoryScores[category] = {
        baseScore: 0,
        hardAssertionBonus: 0,
        strongIndicatorScore: 0,
        ruleScore: 0,
        attributeInfluenceScore: 0,
        finalScore: 0,
        confidence: 0,
        parallelComputedComponents: [],
        computationDurationMs: 0,
        cacheHits: [],
        scoreAggregationSteps: [],
        cappingApplied: false,
      };
    }
    result.scoreBreakdown.categoryScores[category].strongIndicatorScore = seed;
  }

  return { session, email, result, config };
}

