        bodyPlain: 'Your account and credit card statement', // 3 matches: account, credit card, statement
      });
      result.emailId = email.id;

      const indicatorResults = executeStrongIndicators(email, session, result, mockConfig);

      const subjectResults = indicatorResults.filter((r) => r.indicatorType === 'subjectContains');
      const bodyResults = indicatorResults.filter((r) => r.indicatorType === 'bodyContains');

